 17	  TextInput,
 18	} from '@patternfly/react-core';
 19	import { EyeIcon, EyeSlashIcon } from '@patternfly/react-icons';
 20	
 21	import FormGroupHelperText from '../FormGroupHelperText/FormGroupHelperText';
 22	
 23	import { CloudInitNetworkData, CloudInitUserData } from './utils/cloudinit-utils';
 24	import CloudInitEditor from './CloudInitEditor';
 25	import { CloudinitNetworkForm } from './CloudInitNetworkForm';
 26	
 27	type CloudinitFormProps = {
 28	  cloudInitVolume: V1Volume;
 29	  enableNetworkData: boolean;
 30	  networkData: CloudInitNetworkData;
 31	  onEditorSave: (yaml: string) => void;
 32	  setEnableNetworkData: (value: boolean) => void;
 33	  setSubmitDisabled: (value: boolean) => void;
 34	  showEditor: boolean;
 35	  updateNetworkField: (key: keyof CloudInitNetworkData, value: string) => void;
 36	  updateUserField: (key: keyof CloudInitUserData, value: string) => void;
 37	  userData: CloudInitUserData;
 38	};
 39	const CloudinitForm: FC<CloudinitFormProps> = ({
 40	  cloudInitVolume,
 41	  enableNetworkData,
 42	  networkData,
 43	  onEditorSave,
 44	  setEnableNetworkData,
 45	  setSubmitDisabled,
 46	  showEditor,
 47	  updateNetworkField,
 48	  updateUserField,
 49	  userData,
 50	}) => {
 51	  const { t } = useKubevirtTranslation();
 52	  const [passwordHidden, setPasswordHidden] = useState<boolean>(true);
 53	
 54	  return (
 55	    <Fragment key="cloudinit-editor">
 56	      {showEditor ? (
 57	        <Suspense
 58	          fallback={
 59	            <Bullseye>
 60	              <Loading />
 61	            </Bullseye>
 62	          }
 63	        >
 64	          <CloudInitEditor cloudInitVolume={cloudInitVolume} onSave={onEditorSave} />
 65	        </Suspense>
 66	      ) : (
 67	        <Form>
 68	          <FormGroup
 69	            className="kv-cloudint-advanced-tab--validation-text"
 70	            fieldId={'cloudinit-user'}
 71	            isRequired
 72	            label={t('User')}
 73	            required
 74	          >
 75	            <TextInput
 76	              onChange={(_event, v) => {
 77	                setSubmitDisabled(isEmpty(v));
 78	                updateUserField('user', v);
 79	              }}
 80	              id={'cloudinit-user'}
 81	              type="text"
 82	              value={userData?.user || ''}
 83	            />
 84	          </FormGroup>
 85	          <FormGroup
 86	            className="kv-cloudint-advanced-tab--validation-text"
 87	            fieldId={'cloudinit-password'}
 88	            label={t('Password')}
 89	          >
 90	            <InputGroup>
 91	              <InputGroupItem isFill>
 92	                <TextInput
 93	                  id="cloudinit-password"
 94	                  onChange={(_event, v) => updateUserField('password', v)}
 95	                  type={passwordHidden ? 'password' : 'text'}
 96	                  value={userData?.password || ''}
 97	                />
 98	              </InputGroupItem>
 99	              <InputGroupItem>
100	                <Button
101	                  onClick={() => setPasswordHidden(!passwordHidden)}
102	                  variant={ButtonVariant.link}
103	                >
104	                  {passwordHidden ? <EyeIcon /> : <EyeSlashIcon />}
105	                </Button>
106	              </InputGroupItem>
107	            </InputGroup>
108	            <FormGroupHelperText>
109	              <Trans ns="plugin__kubevirt-plugin" t={t}>
110	                Password for this username -{' '}
111	                <Button
112	                  onClick={() =>
113	                    updateUserField(
114	                      'password',
115	                      new RandExp(/[a-z0-9]{4}-[a-z0-9]{4}-[a-z0-9]{4}/).gen(),
116	                    )
117	                  }
118	                  isInline
119	                  variant={ButtonVariant.link}
120	                >
121	                  generate password
122	                </Button>
123	              </Trans>
124	            </FormGroupHelperText>
125	          </FormGroup>
126	          <CloudinitNetworkForm
127	            enableNetworkData={enableNetworkData}
128	            networkData={networkData}
129	            setEnableNetworkData={setEnableNetworkData}
130	            updateNetworkField={updateNetworkField}
131	          />
132	        </Form>
133	      )}
134	    </Fragment>
135	  );
136	};
137	
138	export default CloudinitForm;

